 36→#define _GNU_SOURCE
 37→#include "semihost-private.h"
 38→#include <sys/types.h>
 39→#include <sys/stat.h>
 40→#include <sys/time.h>
 41→#include <fcntl.h>
 42→#include <unistd.h>
 43→#include <string.h>
 44→#include <errno.h>
 45→
 46→struct timeval __semihost_write_time, __semihost_creat_time;
 47→
 48→int
 49→fstat(int fd, struct stat *sbuf)
 50→{
 51→    fd = _map_stdio(fd);
 52→
 53→    int size;
 54→
 55→    if (fd > 0)
 56→        size = sys_semihost_flen(fd);
 57→    else
 58→        size = -1;
 59→
 60→    if (size > 0) {
 61→        sbuf->st_size = size;
 62→        sbuf->st_blksize = 4096;
 63→        sbuf->st_mode = S_IFREG;
 64→    } else {
 65→        sbuf->st_size = 0;
 66→        sbuf->st_blksize = 0;
 67→        sbuf->st_mode = S_IFCHR;
 68→    }
 69→    sbuf->st_ctime = __semihost_creat_time.tv_sec > __semihost_write_time.tv_sec
 70→        ? __semihost_creat_time.tv_sec
 71→        : __semihost_write_time.tv_sec;
 72→    sbuf->st_mtime = __semihost_write_time.tv_sec;
 73→    return 0;
 74→}
